SELECT 
FROM workspace
WHERE owner_user_id = #{ownerUserId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

    AND id > #{lastId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

ORDER BY id ASC
LIMIT #{size}

